import java.util.ArrayList;
import java.util.List;

public class NegativeExample {
    public void method() {
        // This case should NOT be changed because replacing `new ArrayList<String>()` with `new ArrayList<>()`
        // would result in `ArrayList<Object>` being inferred due to the `Object` type of `expr`,
        // which changes the generic type from `String` to `Object`, breaking semantic equivalence.
        // The DSL engine's implicit type inference validation must prevent this transformation.
        Object expr = new ArrayList<String>();

        // Anonymous classes cannot use the diamond operator (Java language restriction).
        // This pattern `new $Type<$Exprs$>()` does not match anonymous classes so it won't apply anyway.
        List<String> yetAnotherList = new ArrayList<String>() {
            private static final long serialVersionUID = 1L;
            @Override
            public String toString() { return ""; }
        };
    }
}

